/* eslint-disable react-hooks/rules-of-hooks */
import React, { useState, useMemo, useRef, useCallback } from 'react';
import PropTypes from 'prop-types';
import { useTranslation } from 'react-i18next';
import { FaCommentDots, FaTimes, FaSearch } from 'react-icons/fa';
import LazyImage from '../components/shared/LazyImage';
import styles from './friendsTabStyles';
import { getFreshActivity } from '../utils/activityUtils';

// -- dynamic style helpers (pass 2) --

// -- extracted inline style constants --

const _st1063 = styles.username;
const _st1064 = styles.status;
const _st1065 = { ...styles.iconButton, color: '#f23f42' };

const IGNORED_APPS = new Set([
    'fps monitor',
    'msi afterburner',
    'rivatuner',
    'fraps',
    'nvidia geforce experience',
    'amd radeon software',
    'obs',
    'obs studio',
    'streamlabs',
    'xsplit',
    'nvidia shadowplay',
    'movavi video suite',
    'movavi',
    'camtasia',
    'bandicam',
    'soundpad',
    'voicemod',
    'teamspeak',
    'mumble',
    'overwolf',
    'razer cortex',
    'steam',
    'epic games launcher',
    'origin',
    'uplay',
    'battle.net',
    'gog galaxy',
    'ea app',
    'xbox app',
    'microsoft store',
]);

const isIgnoredApp = (appName) => {
    if (!appName) return false;
    const lower = appName.toLowerCase().trim();
    for (const ignored of IGNORED_APPS) {
        if (lower.includes(ignored) || ignored.includes(lower)) return true;
    }
    return false;
};

const STATUS_KEYS = {
    online: 'friends.online',
    idle: 'status.idle',
    dnd: 'status.dnd',
    invisible: 'status.invisible',
    offline: 'status.offline',
};
const STATUS_COLOR = {
    online: '#23a559',
    idle: '#f0b232',
    dnd: '#f23f43',
    invisible: '#80848e',
    offline: '#80848e',
};

const getActivityMeta = (activity) => {
    if (activity?.spotify) {
        return {
            icon: '≡ƒÄ╡',
            color: '#1db954',
            background: 'rgba(29, 185, 84, 0.16)',
            text: activity.spotify.track || activity.spotify.name,
        };
    }

    if (activity?.steam && !isIgnoredApp(activity.steam.game || activity.steam.name)) {
        return {
            icon: '≡ƒÄ«',
            color: '#66c0f4',
            background: 'rgba(102, 192, 244, 0.16)',
            text: activity.steam.game || activity.steam.name,
        };
    }

    return null;
};

const FriendsList = ({
    friends,
    onlineUsers = [],
    allUsers = [],
    getDeterministicAvatar,
    onStartDM,
    handleRemoveFriend,
    setActiveTab,
    isLoading = false,
    error = null,
}) => {
    const { t } = useTranslation();
    const [search, setSearch] = useState('');
    const myUsername = localStorage.getItem('chat_username') || '';
    const listRef = useRef(null);

    const handleListKeyDown = useCallback((e) => {
        if (!listRef.current) return;
        const items = Array.from(listRef.current.querySelectorAll('[role="button"][tabindex="0"]'));
        const idx = items.indexOf(document.activeElement);
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            items[(idx + 1) % items.length]?.focus();
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            items[(idx - 1 + items.length) % items.length]?.focus();
        }
    }, []);

    if (isLoading) return <div>{t('common.loading')}</div>;
    if (error) return <div role="alert">{error}</div>;

    const enriched = useMemo(
        () =>
            friends.map((friend) => {
                const iAmSender = friend.sender_username === myUsername;
                const friendUsername = iAmSender
                    ? friend.receiver_username
                    : friend.sender_username;
                const displayAvatar = iAmSender ? friend.receiver_avatar : friend.sender_avatar;
                // Prefer live activity from allUsers (real-time) over the stale DB snapshot on the friend object
                const liveUser = allUsers.find((u) => u.username === friendUsername);
                const friendActivity = getFreshActivity(
                    liveUser?.current_activity ||
                    (iAmSender ? friend.receiver_activity : friend.sender_activity)
                );
                const isReallyOnline =
                    Array.isArray(onlineUsers) && onlineUsers.includes(friendUsername);
                return { ...friend, friendUsername, displayAvatar, friendActivity, isReallyOnline };
            }),
        [friends, onlineUsers, allUsers, myUsername]
    );

    const filtered = useMemo(() => {
        const q = search.toLowerCase();
        const list = q
            ? enriched.filter((f) => f.friendUsername.toLowerCase().includes(q))
            : enriched;
        // sort: online first
        return [...list].sort((a, b) => (b.isReallyOnline ? 1 : 0) - (a.isReallyOnline ? 1 : 0));
    }, [enriched, search]);

    const onlineCount = enriched.filter((f) => f.isReallyOnline).length;

    if (friends.length === 0) {
        return (
            <div style={styles.emptyState}>
                <div>≡ƒÑ║</div>
                <p style={styles.emptyText}>{t('friends.noFriends')}</p>
                <button
                    onClick={() => setActiveTab('add')}
                    style={styles.emptyBtn}
                    aria-label={t('friends.addFriend')}
                >
                    {t('friends.addFriend')}
                </button>
            </div>
        );
    }

    return (
        <div ref={listRef} onKeyDown={handleListKeyDown}>
            {/* Header with search + online count */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '8px', marginTop: '8px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', flex: 1, background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: '8px', padding: '6px 10px' }}>
                    <FaSearch size={11} color="#7a7d87" />
                    <input
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder={t('common.search')}
                        style={{ background: 'transparent', border: 'none', outline: 'none', color: '#dbdee1', fontSize: '13px', width: '100%' }}
                    />
                </div>
                <div style={{ fontSize: '12px', color: '#23a559', fontWeight: '600', whiteSpace: 'nowrap', background: 'rgba(35,165,89,0.1)', border: '1px solid rgba(35,165,89,0.25)', borderRadius: '6px', padding: '4px 8px' }}>
                    ≡ƒƒó {onlineCount} / {friends.length}
                </div>
            </div>

            {filtered.map((friend) => {
                const { id, friendUsername, displayAvatar, friendActivity, isReallyOnline } =
                    friend;
                const friendStatus = isReallyOnline ? 'online' : 'offline';
                const statusText = t(STATUS_KEYS[friendStatus] || 'status.offline', friendStatus);
                const statusColor = STATUS_COLOR[friendStatus] || '#80848e';
                const activityMeta = getActivityMeta(friendActivity);

                return (
                    <div
                        key={id}
                        style={styles.listItem}
                        onMouseEnter={(e) => { e.currentTarget.style.backgroundColor = 'rgba(255,255,255,0.06)'; }}
                        onMouseLeave={(e) => { e.currentTarget.style.backgroundColor = 'transparent'; }}
                    >
                        <div
                            style={styles.userInfo}
                            role="button"
                            tabIndex={0}
                            onClick={() => onStartDM(friendUsername)}
                            onKeyDown={(e) => e.key === 'Enter' && onStartDM(friendUsername)}
                            aria-label={`${t('friends.startDM')} ${friendUsername}`}
                        >
                            <div style={{ position: 'relative', flexShrink: 0 }}>
                                <LazyImage
                                    src={displayAvatar || getDeterministicAvatar(friendUsername)}
                                    style={styles.avatar}
                                    alt={friendUsername}
                                />
                                <span
                                    style={{
                                        position: 'absolute',
                                        bottom: 0,
                                        right: 0,
                                        width: 11,
                                        height: 11,
                                        borderRadius: '50%',
                                        background: statusColor,
                                        border: '2px solid #2b2d31',
                                    }}
                                />
                            </div>
                            <div style={{ minWidth: 0 }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                                    <div style={_st1063}>{friendUsername}</div>
                                    {activityMeta && (
                                        <span
                                            style={{
                                                flexShrink: 0,
                                                display: 'inline-flex',
                                                alignItems: 'center',
                                                justifyContent: 'center',
                                                width: '22px',
                                                height: '22px',
                                                borderRadius: '999px',
                                                background: activityMeta.background,
                                                border: `1px solid ${activityMeta.color}33`,
                                                color: activityMeta.color,
                                                fontSize: '10px',
                                                fontWeight: '700',
                                            }}
                                        >
                                            <span aria-hidden="true">{activityMeta.icon}</span>
                                        </span>
                                    )}
                                </div>
                                <div style={_st1064}>{statusText}</div>
                                {activityMeta && (
                                    <span
                                        style={{
                                            fontSize: '10px',
                                            color: activityMeta.color,
                                            whiteSpace: 'nowrap',
                                            overflow: 'hidden',
                                            textOverflow: 'ellipsis',
                                            marginTop: '2px',
                                        }}
                                    >
                                        {activityMeta.icon} {activityMeta.text}
                                    </span>
                                )}
                            </div>
                        </div>
                        <div style={styles.actions}>
                            <button
                                style={styles.iconButton}
                                title={t('friends.startDM')}
                                aria-label={t('friends.startDM')}
                                onClick={(e) => {
                                    e.stopPropagation();
                                    onStartDM(friendUsername);
                                }}
                            >
                                <FaCommentDots />
                            </button>
                            <button
                                style={_st1065}
                                title={t('friends.removeFriend')}
                                aria-label={t('friends.removeFriend')}
                                onClick={(e) => {
                                    e.stopPropagation();
                                    handleRemoveFriend(id, friendUsername);
                                }}
                            >
                                <FaTimes />
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
    );
};

FriendsList.propTypes = {
    friends: PropTypes.array,
    onlineUsers: PropTypes.func,
    allUsers: PropTypes.array,
    getDeterministicAvatar: PropTypes.func,
    onStartDM: PropTypes.func,
    handleRemoveFriend: PropTypes.func,
    setActiveTab: PropTypes.func,
    isLoading: PropTypes.bool,
    error: PropTypes.string,
};
export default React.memo(FriendsList);

/* eslint-disable jsx-a11y/no-autofocus */
import React, { useState, useRef, useCallback } from 'react';
import PropTypes from 'prop-types';
import { FaUserFriends, FaPaperPlane, FaTimes, FaBell } from '../utils/iconOptimization';
import useFriendsAPI from './useFriendsAPI';
import FriendsList from './FriendsList';
import PendingRequests from './PendingRequests';
import styles from './friendsTabStyles';

import { useTranslation } from 'react-i18next';

// -- extracted inline style constants --

const FriendsTab = ({
    fetchWithAuth,
    apiBaseUrl,
    getDeterministicAvatar,
    onStartDM,
    onClose,
    onPendingCountChange,
    onlineUsers = [],
    allUsers = [],
}) => {
    const { t } = useTranslation();
    const api = useFriendsAPI({ fetchWithAuth, apiBaseUrl, onPendingCountChange });
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState(null);
    const tabBarRef = useRef(null);

    const handleTabBarKeyDown = useCallback((e) => {
        if (!tabBarRef.current) return;
        const tabs = Array.from(tabBarRef.current.querySelectorAll('button'));
        const idx = tabs.indexOf(document.activeElement);
        if (idx === -1) return;
        if (e.key === 'ArrowRight') {
            e.preventDefault();
            tabs[(idx + 1) % tabs.length]?.focus();
        } else if (e.key === 'ArrowLeft') {
            e.preventDefault();
            tabs[(idx - 1 + tabs.length) % tabs.length]?.focus();
        }
    }, []);

    return (
        <div style={styles.container}>
            <div style={styles.topBar}>
                <div style={styles.headerLeft}>
                    <div style={styles.title}>
                        <FaUserFriends />
                        {t('friends.title', 'Arkada┼ƒlar')}
                    </div>
                    <div style={styles.tabButtons} ref={tabBarRef} role="tablist" onKeyDown={handleTabBarKeyDown}>
                        <button
                            style={{
                                ...styles.tabBtn,
                                ...(api.activeTab === 'all' ? styles.activeTabBtn : {}),
                            }}
                            onClick={() => {
                                api.setActiveTab('all');
                                api.setStatusMsg(null);
                            }}
                        >
                            {t('friends.all', 'Hepsi')} ({api.friends.length})
                        </button>
                        <button
                            style={{
                                ...styles.tabBtn,
                                ...(api.activeTab === 'pending' ? styles.activeTabBtn : {}),
                            }}
                            onClick={() => {
                                api.setActiveTab('pending');
                                api.setStatusMsg(null);
                            }}
                        >
                            {t('friends.pending', 'Bekleyenler')}
                            {api.requests.length > 0 && (
                                <span style={styles.badgePulse}>{api.requests.length}</span>
                            )}
                        </button>
                        <button
                            style={{
                                ...styles.addFriendBtn,
                                ...(api.activeTab === 'add' ? styles.activeAddFriendBtn : {}),
                            }}
                            onClick={() => {
                                api.setActiveTab('add');
                                api.setStatusMsg(null);
                            }}
                        >
                            {t('friends.addFriend', 'Arkada┼ƒ Ekle')}
                        </button>
                    </div>
                </div>
                <button onClick={onClose} style={styles.closeHeaderBtn} title={t('common.close')}>
                    <FaTimes />
                </button>
            </div>

            <div style={styles.contentArea}>
                {api.statusMsg && (
                    <div
                        style={{
                            marginBottom: '20px',
                            padding: '12px',
                            borderRadius: '8px',
                            backgroundColor:
                                api.statusMsg.type === 'success'
                                    ? 'rgba(67, 181, 129, 0.2)'
                                    : api.statusMsg.type === 'info'
                                        ? 'rgba(88, 101, 242, 0.2)'
                                        : 'rgba(240, 71, 71, 0.2)',
                            color:
                                api.statusMsg.type === 'success'
                                    ? '#23a559'
                                    : api.statusMsg.type === 'info'
                                        ? '#dee0fc'
                                        : '#f23f42',
                            border: `1px solid ${api.statusMsg.type === 'success' ? '#23a559' : api.statusMsg.type === 'info' ? '#5865f2' : '#f23f42'}`,
                            display: 'flex',
                            alignItems: 'center',
                            gap: '10px',
                            animation: 'fadeIn 0.3s ease',
                        }}
                    >
                        {api.statusMsg.type === 'info' && <FaBell />}
                        {api.statusMsg.text}
                    </div>
                )}

                {api.activeTab === 'add' && (
                    <div style={styles.addSection}>
                        <h3 style={{ color: '#fff', marginBottom: '8px' }}>
                            {t('friends.addFriendTitle', 'ARKADA┼₧ EKLE')}
                        </h3>
                        <p style={{ color: '#b5bac1', fontSize: '0.9em', marginBottom: '16px' }}>
                            {t(
                                'friends.addFriendDesc',
                                t('friendsTab.enterUsername','Enter a username to send a friend request.')
                            )}
                        </p>
                        <form onSubmit={api.handleSendRequest} style={styles.addForm}>
                            {/* eslint-disable-next-line jsx-a11y/no-autofocus */}
                            <input
                                type="text"
                                value={api.addUsername}
                                onChange={(e) => api.setAddUsername(e.target.value)}
                                placeholder={t(
                                    'friends.searchPlaceholder',
                                    t('friendsTab.placeholder','Username or Friend Code (e.g.: 8392014)')
                                )}
                                aria-label={t(
                                    'friends.usernameLabel',
                                    t('friendsTab.placeholder2','Username or friend code')
                                )}
                                style={styles.input}
                                autoFocus
                            />
                            <button type="submit" style={styles.sendRequestBtn}>
                                <FaPaperPlane /> {t('common.send', 'G├╢nder')}
                            </button>
                        </form>
                    </div>
                )}

                {api.activeTab === 'all' && (
                    <div style={styles.listContainer}>
                        <h4 style={styles.listHeader}>
                            {t('friends.friendsCount', 'ARKADA┼₧LAR')} ΓÇö {api.friends.length}
                        </h4>
                        <FriendsList
                            friends={api.friends}
                            onlineUsers={onlineUsers}
                            allUsers={allUsers}
                            getDeterministicAvatar={getDeterministicAvatar}
                            onStartDM={onStartDM}
                            handleRemoveFriend={api.handleRemoveFriend}
                            setActiveTab={api.setActiveTab}
                        />
                    </div>
                )}

                {api.activeTab === 'pending' && (
                    <PendingRequests
                        requests={api.requests}
                        outgoing={api.outgoing}
                        getDeterministicAvatar={getDeterministicAvatar}
                        handleRespond={api.handleRespond}
                    />
                )}
            </div>
        </div>
    );
};

FriendsTab.propTypes = {
    fetchWithAuth: PropTypes.func,
    apiBaseUrl: PropTypes.string,
    getDeterministicAvatar: PropTypes.func,
    onStartDM: PropTypes.func,
    onClose: PropTypes.func,
    onPendingCountChange: PropTypes.func,
    onlineUsers: PropTypes.func,
    allUsers: PropTypes.array,
};
export default React.memo(FriendsTab);

// frontend/src/RoomList/ServerRail.js
import React, { useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import PropTypes from 'prop-types';
import { FaCompass, FaPlus } from '../utils/iconOptimization';
import LazyImage from '../components/shared/LazyImage';
import { styles } from '../styles/SidebarStyles';
import { hapticLight } from '../utils/haptics';

// -- extracted inline style constants --

/**
 * @param {Object} props
 * @param {Array} props.servers - List of server objects to display
 * @param {string|number} props.selectedServerId - Currently selected server ID
 * @param {string|number|null} props.hoveredServerId - Currently hovered server ID
 * @param {Function} props.setHoveredServerId - Set hovered server ID
 * @param {Object} props.safeUnreadCounts - Unread counts per room key
 * @param {Function} props.onHomeClick - Handler for home button click
 * @param {Function} props.handleServerClick - Handler for server icon click
 * @param {Function} props.onDiscoverClick - Handler for discover button click
 * @param {Function} props.onAddClick - Handler for add server button click
 */
const ServerRail = ({
    servers,
    selectedServerId,
    hoveredServerId,
    setHoveredServerId,
    safeUnreadCounts,
    draggedServerId,
    dropTargetIndex,
    dropPosition,
    onHomeClick,
    handleServerClick,
    handleServerContextMenu,
    handleServerDragStartWrapper,
    handleServerDragOverWrapper,
    handleServerDragEndWrapper,
    handleServerDropWrapper,
    onOpenStore,
    onDiscoverClick,
    onAddClick,
}) => {
    const { t } = useTranslation();
    const serverListRef = useRef(null);

    const handleServerListKeyDown = useCallback((e) => {
        if (!serverListRef.current) return;
        const items = Array.from(serverListRef.current.querySelectorAll('[role="button"][tabindex="0"]'));
        const idx = items.indexOf(document.activeElement);
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            items[(idx + 1) % items.length]?.focus();
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            items[(idx - 1 + items.length) % items.length]?.focus();
        }
    }, []);

    const handleHomeHover = useCallback(() => setHoveredServerId('home'), [setHoveredServerId]);
    const handleHomeLeave = useCallback(() => setHoveredServerId(null), [setHoveredServerId]);
    const handleDiscoverHover = useCallback(
        () => setHoveredServerId('discover'),
        [setHoveredServerId]
    );
    const handleDiscoverLeave = useCallback(() => setHoveredServerId(null), [setHoveredServerId]);
    const handleStoreHover = useCallback(() => setHoveredServerId('store'), [setHoveredServerId]);
    const handleStoreLeave = useCallback(() => setHoveredServerId(null), [setHoveredServerId]);
    const handleAddHover = useCallback(() => setHoveredServerId('add'), [setHoveredServerId]);
    const handleAddLeave = useCallback(() => setHoveredServerId(null), [setHoveredServerId]);
    const handleImgError = useCallback((e) => {
        e.target.style.display = 'none';
    }, []);

    return (
        <div style={styles.serverRail} role="navigation" aria-label={t('nav.serverList', 'Server list')}>
            {/* ?? Home Icon */}
            <div>
                <div
                    style={{
                        position: 'absolute',
                        left: 0,
                        width: '4px',
                        height:
                            selectedServerId === 'home'
                                ? '40px'
                                : hoveredServerId === 'home'
                                    ? '20px'
                                    : '0px',
                        backgroundColor: '#fff',
                        borderRadius: '0 4px 4px 0',
                        transition: 'height 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                    }}
                />
                <div
                    style={{
                        ...styles.serverIcon,
                        backgroundColor: selectedServerId === 'home' ? '#5865f2' : '#1a1c1f',
                        borderRadius:
                            selectedServerId === 'home' || hoveredServerId === 'home'
                                ? '16px'
                                : '50%',
                        width: '48px',
                        height: '48px',
                        marginBottom: 0,
                        transition: 'border-radius 0.3s ease, background-color 0.3s ease',
                    }}
                    onClick={onHomeClick}
                    onMouseEnter={handleHomeHover}
                    onMouseLeave={handleHomeLeave}
                    title={t('nav.home', 'Ana Sayfa')}
                    role="button"
                    tabIndex={0}
                    aria-label={t('nav.home', 'Ana Sayfa')}
                    aria-pressed={selectedServerId === 'home'}
                    onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && onHomeClick()}
                >
                    <img
                        src="https://media.pawscord.com/assets/logo.png"
                        alt={t('alt.pawscordLogo', 'Pawscord')}
                        onError={handleImgError}
                    />
                </div>
            </div>
            <div style={styles.separator} />

            {/* Server Icons */}
            <div role="list" aria-label={t('nav.servers', 'Servers')} ref={serverListRef} onKeyDown={handleServerListKeyDown}>
                {servers &&
                    servers.map((server, index) => {
                        const serverName = server.name || '';
                        const initials = (
                            serverName
                                .split(/\s+/)
                                .filter(Boolean)
                                .slice(0, 2)
                                .map((w) => w[0])
                                .join('') ||
                            serverName.substring(0, 2) ||
                            '??'
                        ).toUpperCase();
                        const _hash = serverName.split('').reduce((a, c) => a + c.charCodeAt(0), 0);
                        const _GRAD = [
                            ['#5865f2', '#5865f2'],
                            ['#3ba55d', '#23a559'],
                            ['#f23f42', '#ff6b6b'],
                            ['#faa81a', '#ffca28'],
                            ['#9c59b6', '#c56bcf'],
                            ['#00b0f4', '#00d4ff'],
                        ];
                        const _g = _GRAD[_hash % _GRAD.length];
                        const isActive = selectedServerId === server.id;
                        const isDragging = draggedServerId === server.id;
                        const isDropTarget = dropTargetIndex === index && !isDragging;

                        const serverUnread = Object.keys(safeUnreadCounts)
                            .filter(
                                (k) =>
                                    k.startsWith('room-') &&
                                    server.categories?.some(
                                        (cat) =>
                                            cat &&
                                            cat.rooms?.some((r) => r && `room-${r.slug}` === k)
                                    )
                            )
                            .reduce((sum, k) => sum + (safeUnreadCounts[k] || 0), 0);

                        return (
                            <div key={server.id} role="listitem">
                                {/* Active Pill */}
                                <div
                                    style={{
                                        position: 'absolute',
                                        left: 0,
                                        width: '4px',
                                        height: isActive
                                            ? '40px'
                                            : hoveredServerId === server.id
                                                ? '20px'
                                                : serverUnread > 0
                                                    ? '8px'
                                                    : '0px',
                                        backgroundColor: '#fff',
                                        borderRadius: '0 4px 4px 0',
                                        transition:
                                            'height 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)',
                                    }}
                                />

                                {/* Drop indicator (before) */}
                                {isDropTarget && dropPosition === 'before' && <div />}

                                <div
                                    draggable={true}
                                    onDragStart={(e) =>
                                        handleServerDragStartWrapper(e, server.id, index)
                                    }
