                onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && onOpenStore()}
            >
                ??
            </div>

            {/* Add */}
            <div
                style={{
                    ...styles.serverIcon,
                    backgroundColor: hoveredServerId === 'add' ? '#23a559' : '#1a1c1f',
                    color: hoveredServerId === 'add' ? 'white' : '#23a559',
