                    <div
                        style={styles.modalOverlay}
                        role="button"
                        tabIndex={0}
                        onClick={handleHideNewTagModal}
                        onKeyDown={(e) =>
                            (e.key === 'Enter' || e.key === ' ') && e.currentTarget.click()
                        }
                    >
                        <div
                            style={styles.newTagModal}
                            role="button"
                            tabIndex={0}
