                                    onChange={handleNewTagColorChange}
                                    style={styles.colorPicker}
                                    aria-label={t('bookmarks.tagColor', 'Tag color')}
                                />
                            </div>
                            <div className="flex-10-mt20">
                                <button
                                    aria-label={t('bookmarks.createTagBtn', 'Create tag')}
                                    onClick={createTag}
