                }),
            });

            const data = await response.json();

            const endTime = Date.now();

            setExecTime(endTime - startTime);

            if (response.ok) {
                setOutput(data.output || t('ui.exitti_yok'));

                if (data.error) {
                    setOutput(`Error:\n${data.error}`);
                }
            } else {
                setOutput(`Error: ${data.message || t('ui.kod_calistirilamadi')}`);
            }

            fetchHistory();
        } catch (error) {
            setOutput(t('common.connectionError', 'Ba─ƒlant─▒ hatas─▒'));
        }

        setIsRunning(false);
    };

    const handleStopExecution = async () => {
        try {
            await fetch(`${API_BASE_URL}/code-runner/stop/`, {
                method: 'POST',

                headers: { Authorization: `Bearer ${token}` },
            });

            setIsRunning(false);

            setOutput(t('ui.calistirma_durduruldu'));
        } catch (error) {
            toast.error(t('ui.stop_failed'));
        }
    };

    const handleSaveSnippet = async (name) => {
        try {
            const response = await fetch(`${API_BASE_URL}/code-runner/snippets/`, {
                method: 'POST',

                headers: {
                    Authorization: `Bearer ${token}`,

                    'Content-Type': 'application/json',
                },

                body: JSON.stringify({ name, code, language }),
            });

            if (response.ok) {
                toast.success(t('codeRunner.snippetSaved'));

                fetchSavedSnippets();

                setShowSaveModal(false);
            }
        } catch (error) {
            toast.error(t('codeRunner.saveFailed'));
        }
    };

    const handleLoadSnippet = (snippet) => {
        setCode(snippet.code);

        setLanguage(snippet.language);

        setShowHistory(false);
    };

    const handleDeleteSnippet = async (snippetId) => {
        try {
            await fetch(`${API_BASE_URL}/code-runner/snippets/${snippetId}/`, {
                method: 'DELETE',

                headers: { Authorization: `Bearer ${token}` },
            });

            toast.success(t('codeRunner.snippetDeleted'));

            fetchSavedSnippets();
        } catch (error) {
            toast.error(t('common.deleteFailed'));
        }
    };

    const handleCopyOutput = () => {
        navigator.clipboard.writeText(output);

        toast.success(t('ui.exitti_copied'));
    };

    const handleClearAll = () => {
        setCode('');

        setOutput('');

        setExecTime(null);
    };

    const handleShareToChannel = async () => {
        if (!channelId) {
            toast.warning(t('ui.share_channel_required'));

            return;
        }

        try {
            const response = await fetch(`${API_BASE_URL}/channels/${channelId}/messages/`, {
                method: 'POST',

                headers: {
                    Authorization: `Bearer ${token}`,

                    'Content-Type': 'application/json',
                },

                body: JSON.stringify({
                    content: `\`\`\`${language}\n${code}\n\`\`\`\n**Output:**\n\`\`\`\n${output}\n\`\`\``,
                }),
            });

            if (response.ok) {
                toast.success(t('ui.kanala_paylasildi'));
            }
        } catch (error) {
            toast.error(t('ui.share_failed'));
        }
    };

    // useCallback handlers

    const handleOverlayClick = useCallback(
        (e) => {
            if (e.target.className.includes('code-runner-overlay')) onClose();
        },
        [onClose]
    );

    const handleToggleFullscreen = useCallback(() => setIsFullscreen((prev) => !prev), []);

    const handleToggleHistory = useCallback(() => setShowHistory((prev) => !prev), []);

    const handleShowSaveModal = useCallback(() => setShowSaveModal(true), []);

    const handleHideSaveModal = useCallback(() => setShowSaveModal(false), []);

    const handleCodeChange = useCallback((e) => setCode(e.target.value), []);

    const handleHideHistory = useCallback(() => setShowHistory(false), []);

    return (
        <div
            className={`code-runner-overlay ${isFullscreen ? 'fullscreen' : ''}`}
            role="button"
            tabIndex={0}
            onClick={handleOverlayClick}
            onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && e.currentTarget.click()}
        >
            <div className="code-runner-panel">
                <div className="panel-header">
                    <h2>
                        <FaCode /> {t('codeRunner.title', 'Code Runner')}
                    </h2>

                    <div className="header-actions">
                        <button
                            aria-label={t('codeRunner.toggleFullscreen', 'Toggle fullscreen')}
                            className="fullscreen-btn"
                            onClick={handleToggleFullscreen}
                        >
                            {isFullscreen ? <FaCompress /> : <FaExpand />}
                        </button>

                        <button aria-label={t('common.close', 'Close')} className="close-btn" onClick={onClose}>
                            <FaTimes />
                        </button>
                    </div>
                </div>

                <div className="toolbar">
                    <div className="language-selector">
                        {languages.map((lang) => (
                            <button
                                aria-label={t('codeRunner.selectLang', 'Select {{lang}}', { lang: lang.name })}
                                onClick={() => setLanguage(lang.id)}
                                title={lang.name}
                            >
                                {lang.icon}

                                <span>{lang.name}</span>
                            </button>
                        ))}
                    </div>

                    <div className="toolbar-actions">
                        <button
                            aria-label={t('codeRunner.historyTitle', 'View history')}
                            className="action-btn"
                            onClick={handleToggleHistory}
                        >
                            <FaHistory /> {t('codeRunner.history', 'History')}
                        </button>

                        <button
                            aria-label={t('common.save', 'Save')}
                            className="action-btn"
                            onClick={handleShowSaveModal}
                        >
                            <FaSave /> Save
                        </button>

                        <button
                            aria-label={t('common.clear', 'Clear')}
                            className="action-btn clear"
                            onClick={handleClearAll}
                        >
                            <FaTrash /> Clear
                        </button>
                    </div>
                </div>

                <div className="editor-container">
                    <div className="code-section">
                        <div className="section-header">
                            <span>
                                <FaCode /> Kod
                            </span>

                            <span className="line-count">{code.split('\n').length} sat─▒r</span>
                        </div>

                        <textarea
                            className="code-editor"
                            value={code}
                            onChange={handleCodeChange}
                            placeholder={t('ui.type_your_code_here')}
                            spellCheck="false"
                            aria-label={t('ui.type_your_code_here_2')}
                        />
                    </div>

                    <div className="output-section">
                        <div className="section-header">
                            <span>
                                <FaTerminal /> {t('codeRunner.output', 'Output')}
                            </span>

                            <div className="output-actions">
                                {execTime && (
                                    <span className="exec-time">
                                        <FaClock /> {execTime}ms
                                    </span>
                                )}

                                <button
                                    aria-label={t('common.copyOutput', 'Copy output')}
                                    onClick={handleCopyOutput}
                                    title={t('common.copy', 'Copy')}
                                >
                                    <FaCopy />
                                </button>
                            </div>
                        </div>

                        <pre
                            className={`output-display ${output.includes('Error') ? 'error' : ''}`}
                        >
                            {output || t('ui.exitti_burada_gorunecek')}
                        </pre>
                    </div>
                </div>

                <div className="run-bar">
                    {!isRunning ? (
                        <button
                            aria-label={t('codeRunner.run', 'Run')}
                            className="run-btn"
                            onClick={handleRunCode}
                        >
                            <FaPlay /> {t('codeRunner.run', 'Run')}
                        </button>
                    ) : (
                        <button
                            aria-label={t('codeRunner.stop', 'Stop execution')}
                            className="stop-btn"
                            onClick={handleStopExecution}
                        >
                            <FaStop /> Stop
                        </button>
                    )}

                    {channelId && (
                        <button
                            aria-label={t('codeRunner.shareToChannel', 'Share to channel')}
                            className="share-btn"
                            onClick={handleShareToChannel}
                        >
                            <FaCode /> Channela Share
                        </button>
                    )}
                </div>

                {showHistory && (
                    <div className="history-sidebar">
                        <div className="sidebar-header">
                            <h3>
                                <FaHistory /> {t('codeRunner.historySnippets', 'History & Snippets')}
                            </h3>

                            <button aria-label={t('common.close', 'Close')} onClick={handleHideHistory}>
                                <FaTimes />
                            </button>
                        </div>

                        <div className="sidebar-section">
                            <h4>
                                <FaFolder /> Kaydedilen Snippets
                            </h4>

                            {savedSnippets.length === 0 ? (
                                <p className="empty-msg">{t('codeRunner.noSnippets', 'No code snippets yet')}</p>
                            ) : (
                                <div className="snippets-list">
                                    {savedSnippets.map((snippet) => (
                                        <div key={snippet.id} className="snippet-item">
                                            <div
                                                className="snippet-info"
                                                role="button"
                                                tabIndex={0}
                                                onClick={() => handleLoadSnippet(snippet)}
                                                onKeyDown={(e) =>
                                                    (e.key === 'Enter' || e.key === ' ') &&
                                                    e.currentTarget.click()
                                                }
                                            >
                                                <span className="snippet-name">{snippet.name}</span>

                                                <span className="snippet-lang">
                                                    {snippet.language}
                                                </span>
                                            </div>

                                            <button
                                                aria-label={t('common.delete')}
                                                className="delete-snippet"
                                                onClick={() => handleDeleteSnippet(snippet.id)}
                                            >
                                                <FaTrash />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>

                        <div className="sidebar-section">
                            <h4>
                                <FaClock /> {t('codeRunner.recentRuns', 'Recent Runs')}
                            </h4>

                            {history.length === 0 ? (
                                <p className="empty-msg">{t('codeRunner.noHistory', 'No history')}</p>
                            ) : (
                                <div className="history-list">
                                    {history.slice(0, 10).map((item, index) => (
                                        <div
                                            key={`item-${index}`}
                                            className="history-item"
                                            role="button"
                                            tabIndex={0}
                                            onClick={() => handleLoadSnippet(item)}
                                            onKeyDown={(e) =>
                                                (e.key === 'Enter' || e.key === ' ') &&
                                                e.currentTarget.click()
                                            }
                                        >
                                            <div className="history-info">
                                                <span className="history-lang">
                                                    {item.language}
                                                </span>

                                                <span
                                                    className={`history-status ${item.success ? 'success' : 'error'}`}
                                                >
                                                    {item.success ? (
                                                        <FaCheckCircle />
                                                    ) : (
                                                        <FaExclamationTriangle />
                                                    )}
                                                </span>
                                            </div>

                                            <code className="history-preview">
                                                {item.code?.substring(0, 50)}...
                                            </code>

                                            <span className="history-time">{item.exec_time}ms</span>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {showSaveModal && (
                    <SaveSnippetModal
                        onClose={handleHideSaveModal}
                        onSave={handleSaveSnippet}
                        language={language}
                    />
                )}
            </div>
        </div>
    );
};

const SaveSnippetModal = ({ onClose, onSave, language }) => {
    const { t } = useTranslation();

    const [name, setName] = useState('');

    const handleSubmit = () => {
        if (!name.trim()) {
            toast.warning(t('ui.snippet_adi_gerekli'));

            return;
        }

        onSave(name);
    };

    return (
        <div
            className="modal-overlay"
            role="button"
            tabIndex={0}
            onClick={(e) => e.target.className === 'modal-overlay' && onClose()}
            onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && e.currentTarget.click()}
        >
            <div
                className="save-modal"
                role="dialog"
                aria-modal="true"
                aria-label={t('codeRunner.saveSnippet', 'Save code snippet')}
            >
                <h3>
                    <FaSave /> Snippet Kaydet
                </h3>

                <div className="form-group">
                    <label>{t('codeRunner.snippetName', 'Snippet Name')}</label>

                    <input
                        type="text"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        placeholder={t('ui.orn_fibonacci_hesaplama')}
                        aria-label={t('codeRunner.snippetName', 'Snippet Name')}
                    />
                </div>

                <div className="form-group">
                    <label>Dil</label>

                    <input type="text" value={language} disabled aria-label={t('codeRunner.language', 'Programming language')} />
                </div>

                <div className="modal-actions">
                    <button aria-label={t('common.close', 'Close')} className="cancel-btn" onClick={onClose}>
                        {t('common.cancel')}
                    </button>

                    <button
                        aria-label={t('common.save', 'Save')}
                        className="save-submit-btn"
                        onClick={handleSubmit}
                    >
                        <FaSave /> Save
                    </button>
                </div>
            </div>
        </div>
    );
};

CodeRunnerPanel.propTypes = {
    serverId: PropTypes.string,

    channelId: PropTypes.string,

    onClose: PropTypes.func,
};

SaveSnippetModal.propTypes = {
    onClose: PropTypes.func,

    onSave: PropTypes.func,

    language: PropTypes.string,
};

export default memo(CodeRunnerPanel);

/* eslint-disable jsx-a11y/label-has-associated-control */
import { useState } from 'react';

import PropTypes from 'prop-types';

import { FaTimes, FaPoll, FaPlus, FaTrash, FaClock, FaDownload, FaCalendar } from 'react-icons/fa';

import { toast } from '../../utils/toast';

import { useTranslation } from 'react-i18next';

const EnhancedPollsPanel = ({ fetchWithAuth, apiBaseUrl, onClose, roomSlug }) => {
    const { t } = useTranslation();

    const [question, setQuestion] = useState('');

    const [isLoading, setIsLoading] = useState(false);

    const [options, setOptions] = useState(['', '']);

    const [allowMultiple, setAllowMultiple] = useState(false);

    const [anonymous, setAnonymous] = useState(false);

    const [duration, setDuration] = useState(24); // hours

    const [scheduledFor, setScheduledFor] = useState('');
    const getDurationButtonStyle = (value) => ({
        ...styles.durationButton,
        ...(duration === value ? styles.durationButtonActive : {}),
    });

    const addOption = () => {
        if (options.length < 10) {
            setOptions([...options, '']);
        }
    };

    const removeOption = (index) => {
        if (options.length > 2) {
            setOptions(options.filter((_, i) => i !== index));
        }
    };

    const updateOption = (index, value) => {
        const newOptions = [...options];

        newOptions[index] = value;

        setOptions(newOptions);
    };

    const createPoll = async () => {
        if (!question.trim()) {
            toast.error(t('polls.enterQuestion', 'L├╝tfen bir soru girin'));

            return;
        }

        const validOptions = options.filter((o) => o.trim());

        if (validOptions.length < 2) {
            toast.error(t('polls.addOptions', 'Please add at least 2 options'));

            return;
        }

        try {
            const payload = {
                question: question.trim(),

                options: validOptions,

                allow_multiple: allowMultiple,

                anonymous: anonymous,

                duration_hours: duration,

                room_slug: roomSlug,
            };

            if (scheduledFor) {
                payload.scheduled_for = new Date(scheduledFor).toISOString();
            }

            await fetchWithAuth(`${apiBaseUrl}/polls/create/`, {
                method: 'POST',

                headers: { 'Content-Type': 'application/json' },

                body: JSON.stringify(payload),
            });

            toast.success(
                scheduledFor
                    ? t('polls.pollScheduled', 'Anket ba┼ƒar─▒yla planland─▒')
                    : t('polls.pollCreated', 'Anket ba┼ƒar─▒yla olu┼ƒturuldu')
            );

            onClose();
        } catch (error) {
            toast.error(t('polls.createFailed', 'Anket olu┼ƒturulamad─▒'));
        }
    };

    const exportResults = async (pollId) => {
        try {
            const response = await fetchWithAuth(`${apiBaseUrl}/polls/${pollId}/export/`);

            const data = await response.json();

            const csv = [
                ['Option', 'Votes', 'Percentage'],

                ...data.results.map((r) => [r.option, r.votes, `${r.percentage}%`]),
            ]
                .map((row) => row.join(','))
                .join('\n');

            const blob = new Blob([csv], { type: 'text/csv' });

            const url = window.URL.createObjectURL(blob);

            const a = document.createElement('a');

            a.href = url;

            a.download = `poll_results_${pollId}.csv`;

            document.body.appendChild(a);

            a.click();

            window.URL.revokeObjectURL(url);

            document.body.removeChild(a);

            toast.success(t('polls.resultsExported', 'Sonu├ºlar d─▒┼ƒa aktar─▒ld─▒'));
        } catch (error) {
            toast.error(t('polls.exportFailed', 'Sonu├ºlar d─▒┼ƒa aktar─▒lamad─▒'));
        }
    };

    const durationOptions = [
        { value: 1, label: t('polls.1hour', '1 Hour') },

        { value: 6, label: t('polls.6hours', '6 Hours') },

        { value: 12, label: t('polls.12hours', '12 Hours') },

        { value: 24, label: t('polls.1day', '1 Day') },

        { value: 48, label: t('polls.2days', '2 Days') },

        { value: 72, label: t('polls.3days', '3 Days') },

        { value: 168, label: t('polls.1week', '1 Week') },
    ];

    return (
        <div style={styles.overlay}>
            <div style={styles.modal}>
                <div style={styles.header}>
                    <div style={styles.headerLeft}>
                        <FaPoll className="icon-primary-mr10" />

                        <h2 style={styles.title}>{t('polls.createPoll', 'Anket Olu┼ƒtur')}</h2>
                    </div>

                    <button aria-label={t('common.close', 'Close')} onClick={onClose} style={styles.closeButton}>
                        <FaTimes />
                    </button>
                </div>

                <div style={styles.content}>
                    <div style={styles.section}>
                        <label style={styles.label}>{t('polls.question', 'Question')}</label>

                        <input
                            type="text"
                            value={question}
                            onChange={(e) => setQuestion(e.target.value)}
                            placeholder={t('polls.whatsYourQuestion', "What's your question?")}
                            style={styles.input}
                            maxLength={200}
                            aria-label={t('polls.questionInput', 'Poll question')}
                        />
                    </div>

                    <div style={styles.section}>
                        <div style={styles.sectionHeader}>
                            <label style={styles.label}>{t('polls.options', 'Options')}</label>

                            <button
                                aria-label={t('polls.addOption', 'Add option')}
                                onClick={addOption}
                                style={styles.addButton}
                                disabled={options.length >= 10}
                            >
                                <FaPlus className="mr-6" />

                                {t('polls.addOption', 'Se├ºenek Ekle')}
                            </button>
                        </div>

                        <div style={styles.optionsList}>
                            {options.map((option, idx) => (
                                <div key={`item-${idx}`} style={styles.optionRow}>
                                    <input
                                        type="text"
                                        value={option}
                                        onChange={(e) => updateOption(idx, e.target.value)}
                                        placeholder={`Option ${idx + 1}`}
                                        style={styles.optionInput}
                                        maxLength={100}
                                        aria-label={t('polls.optionInput', `Option ${idx + 1}`)}
                                    />

                                    {options.length > 2 && (
                                        <button
                                            aria-label={t('polls.removeOption', 'Remove option')}
                                    style={styles.removeButton}
                                    title={t('common.remove', 'Remove')}
                                        >
                                    <FaTrash />
                                </button>
                            )}
                        </div>
                            ))}
                    </div>
                </div>

                <div style={styles.section}>
                    <label style={styles.label}>{t('polls.duration', 'Duration')}</label>

                    <div style={styles.durationGrid}>
                        {durationOptions.map((opt) => (
                            <button
                                aria-label={t('polls.selectDuration', opt.label)}
                                onClick={() => setDuration(opt.value)}
                                style={getDurationButtonStyle(opt.value)}
                            >
                                {opt.label}
                            </button>
                        ))}
                    </div>
                </div>

                <div style={styles.section}>
                    <label style={styles.label}>
                        <FaCalendar className="mr-6" />

                        {t('polls.scheduleOptional', 'Schedule (Optional)')}
                    </label>

                    <input
                        type="datetime-local"
                        value={scheduledFor}
                        onChange={(e) => setScheduledFor(e.target.value)}
                        style={styles.input}
                        min={new Date().toISOString().slice(0, 16)}
                    />

                    {scheduledFor && (
                        <div style={styles.hint}>
                            Poll will be posted on {new Date(scheduledFor).toLocaleString()}
                        </div>
                    )}
                </div>

                <div style={styles.checkboxes}>
                    <label style={styles.checkbox}>
                        <input
                            type="checkbox"
                            checked={allowMultiple}
                            onChange={(e) => setAllowMultiple(e.target.checked)}
                        />

                        <span style={styles.checkboxLabel}>
                            {t('polls.allowMultiple', '├çoklu se├ºime izin ver')}
                        </span>
                    </label>
                    <label style={styles.checkbox}>
                        <input
                            type="checkbox"
                            checked={anonymous}
                            onChange={(e) => setAnonymous(e.target.checked)}
                        />

                        <span style={styles.checkboxLabel}>
                            {t('polls.anonymousVoting', 'Anonim oylama')}
                        </span>
                    </label>
                </div>

                <button
                    aria-label={t('polls.createPollBtn', 'Create poll')}
                    onClick={createPoll}
                    style={styles.createButton}
                >
                    {scheduledFor
                        ? t('polls.schedulePoll', 'Anketi Zamanla')
                        : t('polls.createPoll', 'Anket Olu┼ƒtur')}
                </button>
            </div>
        </div>
        </div >
    );
};

