import { useState, useEffect } from 'react';

import PropTypes from 'prop-types';

import { FaTimes, FaFilter, FaPlus, FaTrash } from 'react-icons/fa';

import toast from '../../utils/toast';

import { useTranslation } from 'react-i18next';

import logger from '../../utils/logger';

/**





 * ≡ƒÄëΓÇç Keyword Mutes Panel





 * Kelime bazl message filterleme





 */

const KeywordMutesPanel = ({ fetchWithAuth, apiBaseUrl, onClose }) => {
    const { t } = useTranslation();

    const [keywords, setKeywords] = useState([]);

    const [newKeyword, setNewKeyword] = useState('');

    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadKeywords();
    }, []);

    const loadKeywords = async () => {
        try {
            setLoading(true);

            const response = await fetchWithAuth(`${apiBaseUrl}/mutekeyword/list/`);

            if (response.ok) {
                const data = await response.json();

                setKeywords(data);
            }
        } catch (error) {
            logger.error(t('ui.keyword_load_hatasi'), error);
        } finally {
            setLoading(false);
        }
    };

    const addKeyword = async () => {
        if (!newKeyword.trim()) {
            toast.error(t('keywordMutes.wordRequired'));

            return;
        }

        try {
            const response = await fetchWithAuth(`${apiBaseUrl}/mutekeyword/add/`, {
                method: 'POST',

                headers: { 'Content-Type': 'application/json' },

                body: JSON.stringify({ keyword: newKeyword.trim() }),
            });

            if (response.ok) {
                toast.success(t('keywordMutes.wordAdded'));

                setNewKeyword('');

                loadKeywords();
            } else {
                toast.error(t('keywordMutes.wordAddFailed'));
            }
        } catch (error) {
            logger.error(t('ui.keyword_addme_hatasi'), error);

            toast.error(t('common.error'));
        }
    };

    const removeKeyword = async (keywordId) => {
        try {
            const response = await fetchWithAuth(`${apiBaseUrl}/mutekeyword/remove/`, {
                method: 'DELETE',

                headers: { 'Content-Type': 'application/json' },

                body: JSON.stringify({ keyword_id: keywordId }),
            });

            if (response.ok) {
                toast.success(t('keywordMutes.wordRemoved'));

                loadKeywords();
            } else {
                toast.error(t('ui.kelime_kaldirilamadi'));
            }
        } catch (error) {
            logger.error(t('ui.keyword_kaldirma_hatasi'), error);

            toast.error(t('common.error'));
        }
    };

    return (
        <div
            style={styles.overlay}
            role="button"
            tabIndex={0}
            onClick={onClose}
            onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && e.currentTarget.click()}
        >
            <div
                style={styles.modal}
                role="button"
                tabIndex={0}
                onClick={(e) => e.stopPropagation()}
                onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && e.currentTarget.click()}
            >
                <div style={styles.header}>
                    <div className="flex-align-10">
                        <FaFilter className="icon-danger" />

                        <h2 className="m-0">Kelime Filtreleri</h2>
                    </div>

                    <FaTimes onClick={onClose} style={styles.closeBtn} />
                </div>

                <div style={styles.addSection}>
                    <input
                        type="text"
                        value={newKeyword}
                        onChange={(e) => setNewKeyword(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && addKeyword()}
                        placeholder={t('keywordMutes.keyword', 'Enter word/phrase to filter...')}
                        style={styles.input}
                        aria-label={t('keywordMutes.newKeyword', 'New keyword')}
                    />

                    <button aria-label={t('keywordMutes.addKeyword', 'Add keyword')} onClick={addKeyword} style={styles.addBtn}>
                        <FaPlus /> Add
                    </button>
                </div>

                <div style={styles.content}>
                    {loading ? (
                        <div style={styles.loading}>{t('common.loading')}</div>
                    ) : keywords.length === 0 ? (
                        <div style={styles.empty}>
                            <FaFilter className="icon-lg-mb10" />

                            <p>{t('keywordMutes.noKeywords', 'No filtered keywords yet')}</p>

                            <p className="text-gray-12">
                                {t('keywordMutes.hint', 'Messages containing these words will be hidden from you')}
                            </p>
                        </div>
                    ) : (
                        <div style={styles.keywordList}>
                            {keywords.map((kw) => (
                                <div key={kw.id} style={styles.keywordItem}>
                                    <div style={styles.keywordText}>
                                        <FaFilter className="text-888-14" />

                                        <span>{kw.keyword}</span>
                                    </div>

                                    <button
                                        aria-label={t('keywordMutes.removeKeyword', 'Remove keyword')}
                                        onClick={() => removeKeyword(kw.id)}
                                        style={styles.removeBtn}
                                    >
                                        <FaTrash />
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                <div style={styles.footer}>
                    <div style={styles.hint}>
                        {t('keywordMutes.tip', '≡ƒÆí Tip: Messages containing these words will not be shown to you')}
                    </div>
                </div>
            </div>
        </div>
    );
};

